import{_ as t,o,c as a,a2 as r}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"OpenSIN-AI Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/opensin-ai-overview.md","filePath":"guide/opensin-ai-overview.md"}'),n={name:"guide/opensin-ai-overview.md"};function d(i,e,c,s,p,l){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="opensin-ai-overview" tabindex="-1">OpenSIN-AI Overview <a class="header-anchor" href="#opensin-ai-overview" aria-label="Permalink to &quot;OpenSIN-AI Overview&quot;">​</a></h1><p>OpenSIN-AI is an ecosystem for autonomous agents, fleet orchestration, and multi-surface product delivery. This page is a public overview for users and contributors. It is not the organizational SSOT.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Canonical ownership, repo mapping, and consolidation state live in <a href="https://github.com/OpenSIN-AI/OpenSIN-overview" target="_blank" rel="noreferrer"><code>OpenSIN-overview</code></a>. This page summarizes the current model for docs users.</p></div><h2 id="the-product-model" tabindex="-1">The Product Model <a class="header-anchor" href="#the-product-model" aria-label="Permalink to &quot;The Product Model&quot;">​</a></h2><p>OpenSIN currently operates across three product-facing layers:</p><table tabindex="0"><thead><tr><th>Surface</th><th>Domain</th><th>Canonical Repo</th><th>Purpose</th></tr></thead><tbody><tr><td>Marketing</td><td><code>opensin.ai</code></td><td><code>website-opensin.ai</code></td><td>Open-source landing site and product story</td></tr><tr><td>Marketplace</td><td><code>my.opensin.ai</code></td><td><code>website-my.opensin.ai</code></td><td>Paid-layer marketing, plans, bundles, conversion</td></tr><tr><td>Dashboard</td><td><code>chat.opensin.ai</code></td><td><code>OpenSIN-WebApp</code></td><td>Authenticated fleet control and user application</td></tr></tbody></table><p>The public documentation at <code>docs.opensin.ai</code> belongs to <code>OpenSIN-documentation</code> and explains how to use and build with the system.</p><h2 id="core-repositories" tabindex="-1">Core Repositories <a class="header-anchor" href="#core-repositories" aria-label="Permalink to &quot;Core Repositories&quot;">​</a></h2><p>These are the canonical core repos users and contributors should know first:</p><table tabindex="0"><thead><tr><th>Repo</th><th>Role</th></tr></thead><tbody><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN" target="_blank" rel="noreferrer"><code>OpenSIN</code></a></td><td>Python kernel and flagship core platform</td></tr><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN-Code" target="_blank" rel="noreferrer"><code>OpenSIN-Code</code></a></td><td>Autonomous TypeScript coding CLI</td></tr><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN-backend" target="_blank" rel="noreferrer"><code>OpenSIN-backend</code></a></td><td>A2A fleet control plane</td></tr><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN-WebApp" target="_blank" rel="noreferrer"><code>OpenSIN-WebApp</code></a></td><td>Authenticated dashboard at <code>chat.opensin.ai</code></td></tr><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN-documentation" target="_blank" rel="noreferrer"><code>OpenSIN-documentation</code></a></td><td>Public docs website</td></tr><tr><td><a href="https://github.com/OpenSIN-AI/OpenSIN-overview" target="_blank" rel="noreferrer"><code>OpenSIN-overview</code></a></td><td>Organizational SSOT and repo map</td></tr></tbody></table><h2 id="supporting-repo-families" tabindex="-1">Supporting Repo Families <a class="header-anchor" href="#supporting-repo-families" aria-label="Permalink to &quot;Supporting Repo Families&quot;">​</a></h2><p>OpenSIN uses a clear naming model for supporting repos:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Meaning</th><th>Examples</th></tr></thead><tbody><tr><td><code>Team-SIN-*</code></td><td>Team monorepos for specialist workers</td><td><code>Team-SIN-Code-Core</code></td></tr><tr><td><code>Infra-SIN-*</code></td><td>Infrastructure, setup, and config SSOT</td><td><code>Infra-SIN-Dev-Setup</code>, <code>Infra-SIN-OpenCode-Stack</code></td></tr><tr><td><code>Biz-SIN-*</code></td><td>Marketing and business content</td><td><code>Biz-SIN-Marketing</code>, <code>Biz-SIN-Blog-Posts</code></td></tr><tr><td><code>Template-SIN-*</code></td><td>Blueprints and scaffolds</td><td><code>Template-SIN-Agent</code></td></tr></tbody></table><h2 id="current-canonical-web-surfaces" tabindex="-1">Current Canonical Web Surfaces <a class="header-anchor" href="#current-canonical-web-surfaces" aria-label="Permalink to &quot;Current Canonical Web Surfaces&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Domain</th><th>Surface Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>opensin.ai</code></td><td>Public marketing</td><td>Open-source landing surface</td></tr><tr><td><code>my.opensin.ai</code></td><td>Marketplace</td><td>Paid layer and conversion surface</td></tr><tr><td><code>chat.opensin.ai</code></td><td>Authenticated app</td><td>Dashboard, fleet interaction, control</td></tr><tr><td><code>docs.opensin.ai</code></td><td>Documentation</td><td>Public end-user docs</td></tr><tr><td><code>blog.opensin.ai</code></td><td>Blog</td><td>Public content and announcements</td></tr></tbody></table><h2 id="important-consolidation-rules" tabindex="-1">Important Consolidation Rules <a class="header-anchor" href="#important-consolidation-rules" aria-label="Permalink to &quot;Important Consolidation Rules&quot;">​</a></h2><ul><li><code>opensin-ai-code</code> is no longer a canonical standalone repo. Its absorbed reference material lives in <code>OpenSIN/opensin_agent_platform/</code>.</li><li><code>opensin-ai-cli</code> and <code>opensin-ai-platform</code> are rationalization-pending repos. Do not position them as the primary recommended path for new work.</li><li>New OpenCode config links must use the canonical in-org paths: <code>OpenSIN-AI/Infra-SIN-OpenCode-Stack</code> and <code>OpenSIN-AI/Infra-SIN-Global-Brain</code>.</li></ul><h2 id="where-to-go-next" tabindex="-1">Where To Go Next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where To Go Next&quot;">​</a></h2><ul><li>Want to use OpenSIN: <a href="/guide/getting-started.html">Getting Started</a></li><li>Want to understand surfaces: <a href="/governance/domain-registry.html">Domain Registry</a></li><li>Want to build with the engine: <a href="/sdk/overview.html">SDK Overview</a></li><li>Want the org-wide source of truth: <a href="https://github.com/OpenSIN-AI/OpenSIN-overview" target="_blank" rel="noreferrer"><code>OpenSIN-overview</code></a></li></ul>',19)])])}const b=t(n,[["render",d]]);export{u as __pageData,b as default};
